module mux4_1
(
  input [3:0] mux_input,
  input [1:0] select,
  output reg data_out
);

  always @(*)
  begin
    case (select)
      2'b00: data_out = mux_input[0];
      2'b01: data_out = mux_input[1];
      2'b10: data_out = mux_input[2];
      2'b11: data_out = mux_input[3];
      default: data_out = 1'b0;
    endcase
  end

endmodule
